// Compact metadata solution to avoid transaction size limits

// Create minimal metadata without embedding large files
export function createCompactMetadata(name, description, mediaType, creator, tokenId) {
  const metadata = {
    name: name,
    description: description,
    attributes: [{
      trait_type: "Media Type",
      value: mediaType
    }, {
      trait_type: "Creator",
      value: creator
    }, {
      trait_type: "Storage",
      value: "Compact"
    }, {
      trait_type: "Token ID",
      value: tokenId.toString()
    }, {
      trait_type: "Created",
      value: new Date().toISOString()
    }],
    // IMPORTANT: No embedded file data to keep transaction small
    local_file_key: `nft_file_${tokenId}`,
    compact_storage: true,
    version: "1.0"
  };
  return metadata;
}

// Store file reference separately from metadata
export async function storeFileReference(file, tokenId) {
  try {
    // Store only file info, not the actual file data
    const fileInfo = {
      name: file.name,
      type: file.type,
      size: file.size,
      lastModified: file.lastModified,
      tokenId: tokenId,
      timestamp: Date.now()
    };
    const storageKey = `nft_file_ref_${tokenId}`;
    localStorage.setItem(storageKey, JSON.stringify(fileInfo));

    // Store the actual file separately with size limit
    const maxSize = 2 * 1024 * 1024; // 2MB limit for file storage
    if (file.size <= maxSize) {
      const base64Data = await fileToBase64(file);
      const fileStorageKey = `nft_file_data_${tokenId}`;
      localStorage.setItem(fileStorageKey, base64Data);
    }
    return {
      success: true,
      storageKey: storageKey,
      fileDataKey: file.size <= maxSize ? `nft_file_data_${tokenId}` : null
    };
  } catch (error) {
    console.error('Error storing file reference:', error);
    return {
      success: false,
      error: error.message
    };
  }
}

// Convert file to base64 (helper function)
function fileToBase64(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result);
    reader.onerror = error => reject(error);
  });
}

